      - IS NULL, IS NOT NULL
      - Boolean connectors: AND, OR (AND has higher precedence)
    """
    tokens = _tokenize_where(where)
    if not tokens:
        raise ValueError("Empty WHERE clause")

    # Convert tokens to postfix (RPN) using shunting-yard (AND > OR)
    output: List[Any] = []
